vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 orig = vUv;

    float inv_zoom = 1;//min(uAspect.x,uAspect.y)*1.0;
    //float t = clamp01(uTime*0.33);
    //t = t*t*(3 - 2*t);
    //inv_zoom = mix(1, inv_zoom, t);

    vUv -= 0.5;
    vUv *= inv_zoom;
    vUv *= uAspect.xy;


    vec4 N1 = texture(sampler_fw_noise_hq, vUv*uTexSize.xy*.1*texsize_noise_hq.zw/64 +rand_preset.xy)*1;
    vec4 N2 = texture(sampler_fw_noise_hq, vUv*uTexSize.xy*.1*texsize_noise_hq.zw/16+rand_preset.xy)*0.25;
    vec4 N3 = texture(sampler_fw_noise_hq, vUv*uTexSize.xy*.1*texsize_noise_hq.zw/32+rand_preset.xy)*0.5;

    vUv = 0.05 + 0.9*vUv;
    vUv.x += 0.05*cos((N1.x + N2.x + N3.x)*5 + audioLowSmooth*.2+uTime*4.13);
    vUv.y += 0.05*sin((N1.y + N2.y + N3.y)*5 + audioHighSmooth*.2+uTime*5);
    vec2 uv2;
    uv2.x = vUv.x*cos(q1) - vUv.y*sin(q1);
    uv2.y = vUv.x*sin(q1) + vUv.y*cos(q1);
    uv2 *= uAspect.zw;
    uv2 += 0.455;

uv2=abs(fract(uv2+.5)-.5) ;
    ret = abs( texture(sampler_main, uv2).xyz*2.65
                            + GetBlur1(uv2)*-2 );

    ret.xyz *= 1.5;

  fragColor = ret;
}
